CustomField.formula:
if(
AND(
NOT( ISNULL(Parent.Name) ), NOT( Ultimate_Parent__c = Name ), Parent.RecordTypeId = '0121i000000g5nQ',/*Grouping Entity*/
OR(
/*All segmentations except Bank and IFA*/ AND( CONTAINS( Parent.Name ,TEXT(Sub_Type__c)), TEXT(Sub_Type__c) <> 'Bank', TEXT(Sub_Type__c) <> 'IFA'),
/*IFA*/ AND( CONTAINS( Parent.Name ,'IFA'), NOT(CONTAINS( Parent.Name ,'Network')), TEXT(Sub_Type__c) = 'IFA'),
/*Bank*/ AND( CONTAINS( Parent.Name ,'Bank'), NOT(CONTAINS( Parent.Name ,'Network')), NOT(CONTAINS( Parent.Name ,'Private')), NOT(CONTAINS( Parent.Name ,'Retail')), TEXT(Sub_Type__c) = 'Bank')
)/* End of OR*/ ) /* End of AND*/ ,1,0) /* End of IF*/
